import type React from 'react';

import { cva } from 'class-variance-authority';

import { cn } from '../utils/cn';
import { Chip } from './Chip';
import type { ChipProps } from './Chip';

const toggleChipVariants = cva([
  'group/toggle-chip',
  'border border-brand-grey-800',
  'data-[state=on]:border-primary data-[state=on]:bg-btn-pressed data-[state=on]:text-btn-primary',
]);

interface ToggleChipOwnProps {
  children: React.ReactNode;
  /** Whether the chip should be shown as enabled. */
  pressed?: boolean;
}

export type ToggleChipProps = ToggleChipOwnProps & ChipProps;

/**
 * A non-interactive chip that represents an on or off state. Combines Chip with
 * Toggle styling.
 *
 * Use Toggle if you need interactivity.
 */
function ToggleChip({ pressed, className, ...chipProps }: ToggleChipProps) {
  return (
    <Chip
      data-state={pressed ? 'on' : 'off'}
      className={cn(toggleChipVariants(), className)}
      {...chipProps}
    />
  );
}

export { ToggleChip };
